mapper.select:
SELECT * FROM (SELECT ROW_NUMBER() OVER (ORDER BY A2.BBS_ID DESC) AS RNUM , COALESCE(A2.BBS_ID , '') AS BBS_ID , COALESCE(A2.SITE_ID , '') AS SITE_ID , COALESCE(A2.BBS_SE , '') AS BBS_SE , COALESCE(A2.BBS_NM , '') AS BBS_NM , COALESCE(A2.BBS_DE , '') AS BBS_DE , COALESCE(A2.TAG_USE_YN , '') AS TAG_USE_YN , COALESCE(A2.ATCH_FILE_CNT , '') AS ATCH_FILE_CNT , COALESCE(A2.ATCH_FILE_SIZE , '') AS ATCH_FILE_SIZE , COALESCE(A2.REPLY_YN , '') AS REPLY_YN , COALESCE(A2.COMMENT_YN , '') AS COMMENT_YN , COALESCE(DATE_FORMAT(A2.CRT_DATE , '%Y-%m-%d') , '') AS CRT_DATE , COALESCE(D2.CHG_USER_ID , '') AS CHG_USER_ID , COALESCE(A2.STTUS_CODE , '') AS STTUS_CODE , CASE WHEN COALESCE(A2.STTUS_CODE , '') = 'A' THEN '정상' ELSE '삭제' END AS STTUS_CODE_NM , COALESCE(B2.CODE_NM , '') AS BBS_SE_NM FROM ARMBORD A2 LEFT OUTER JOIN (SELECT CODE_ID , CODE , CODE_NM FROM LETTCCMMNDETAILCODE WHERE CODE_ID = 'ARM001' AND USE_AT = 'Y') B2 ON A2.BBS_SE = B2.CODE LEFT OUTER JOIN (SELECT D3.ESNTL_ID , D3.EMPLYR_ID AS CHG_USER_ID , D3.USER_NM AS USER_NM FROM LETTNEMPLYRINFO D3) D2 ON A2.CHG_USER_ID = D2.ESNTL_ID WHERE A2.STTUS_CODE = 'A'
AND A2.BBS_NM LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.BBS_DE LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.TARGET_GBN = #{targetGbn}
AND A2.BBS_NM LIKE CONCAT('%', #{filterBbsNm}, '%')
AND A2.BBS_DE LIKE CONCAT('%', #{filterBbsDe}, '%')
AND B2.CODE_NM LIKE CONCAT('%', #{filterBbsSeNm}, '%')
AND A2.STTUS_CODE = #{filterSttusCode}
) A1 LIMIT #{lengthPage} OFFSET #{startIndex}

SELECT COUNT(1) AS LIST_CNT FROM (SELECT ROW_NUMBER() OVER (ORDER BY A2.BBS_ID) AS RNUM , COALESCE(A2.BBS_ID , '') AS BBS_ID , COALESCE(A2.SITE_ID , '') AS SITE_ID , COALESCE(A2.BBS_SE , '') AS BBS_SE , COALESCE(A2.BBS_NM , '') AS BBS_NM , COALESCE(A2.BBS_DE , '') AS BBS_DE , COALESCE(A2.TAG_USE_YN , '') AS TAG_USE_YN , COALESCE(A2.ATCH_FILE_CNT , '') AS ATCH_FILE_CNT , COALESCE(A2.ATCH_FILE_SIZE , '') AS ATCH_FILE_SIZE , COALESCE(A2.REPLY_YN , '') AS REPLY_YN , COALESCE(A2.COMMENT_YN , '') AS COMMENT_YN , COALESCE(DATE_FORMAT(A2.CRT_DATE , '%Y-%m-%d') , '') AS CRT_DATE , COALESCE(D2.CHG_USER_ID , '') AS CHG_USER_ID , COALESCE(A2.STTUS_CODE , '') AS STTUS_CODE , COALESCE(B2.CODE_NM , '') AS CODE_NM FROM ARMBORD A2 LEFT OUTER JOIN (SELECT CODE_ID , CODE , CODE_NM FROM LETTCCMMNDETAILCODE WHERE CODE_ID = 'ARM001' AND USE_AT = 'Y') B2 ON A2.BBS_SE = B2.CODE LEFT OUTER JOIN (SELECT D3.ESNTL_ID , D3.EMPLYR_ID AS CHG_USER_ID , D3.USER_NM AS USER_NM FROM LETTNEMPLYRINFO D3) D2 ON A2.CHG_USER_ID = D2.ESNTL_ID WHERE A2.STTUS_CODE = 'A'
AND A2.BBS_NM LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.BBS_DE LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.TARGET_GBN = #{targetGbn}
AND A2.BBS_NM LIKE CONCAT('%', #{filterBbsNm}, '%')
AND A2.BBS_DE LIKE CONCAT('%', #{filterBbsDe}, '%')
AND B2.CODE_NM LIKE CONCAT('%', #{filterBbsSeNm}, '%')
AND A2.STTUS_CODE = #{filterSttusCode}
)A1

mapper.insert:
    INSERT INTO ARMBORD ( BBS_ID
                        , SITE_ID
                        , TARGET_GBN
                        , BBS_SE
                        , BBS_NM
                        , BBS_DE
                        , TAG_USE_YN
                        , ATCH_FILE_CNT
                        , ATCH_FILE_SIZE
                        , REPLY_YN
                        , COMMENT_YN
                        , READ_ROLE
                        , WRITE_ROLE
                        , DELETE_ROLE
                        , SECRET_YN
                        , CAPTCHA_AT
                        , PASS_AT
                        , PAGE_PER_LEN
                        , PAGE_LEN
                        , USE_MHRLS
                        , CHRG_DEPT
                        , CHARGER_NM
                        , TLPHON_NO
                        , STTUS_CODE
                        , CHG_USER_ID
                        , CRT_DATE
                        , CHG_DATE
               ) VALUES ( #{bbsId}
                        , #{siteId} 
                        , #{targetGbn}
                        , #{bbsSe}
                        , #{bbsNm}
                        , #{bbsDe}
                        , #{tagUseYn}
                        , #{atchFileCnt}
                        , #{atchFileSize}
                        , #{replyYn}
                        , #{commentYn}
                        , #{readRole}
                        , #{writeRole}
                        , #{deleteRole}
                        , #{secretYn}
                        , #{captchaAt}
                        , #{passAt}
                        , #{pagePerLen}
                        , #{pageLen}
                        , #{useMhrls}
                        , #{chrgDept}
                        , #{chargerNm}
                        , REPLACE( #{tlphonNo} , '-', '' )
                        , #{sttusCode}
                        , #{uniqId}
                        , NOW()
                        , NOW()
)

mapper.update:
UPDATE ARMBORD
                SET SITE_ID = #{siteId}
                  , BBS_SE  = #{bbsSe}
                  , BBS_NM  = #{bbsNm}
                  , BBS_DE  = #{bbsDe}
                  , TAG_USE_YN  = #{tagUseYn}
                  , ATCH_FILE_CNT  = #{atchFileCnt}
                  , ATCH_FILE_SIZE  = #{atchFileSize}
                  , REPLY_YN  = #{replyYn}
                  , COMMENT_YN  = #{commentYn}
                  , READ_ROLE  = #{readRole}
                  , WRITE_ROLE  = #{writeRole}
                  , DELETE_ROLE  = #{deleteRole}
                  , SECRET_YN  = #{secretYn}
                  , CAPTCHA_AT  = #{captchaAt}
                  , PASS_AT  = #{passAt}
                  , PAGE_PER_LEN  = #{pagePerLen}
                  , PAGE_LEN  = #{pageLen}
                  , USE_MHRLS  = #{useMhrls}
                  , CHRG_DEPT  = #{chrgDept}
                  , CHARGER_NM  = #{chargerNm}
                  , TLPHON_NO  = REPLACE( #{tlphonNo} , '-', '' )
                  , STTUS_CODE  = #{sttusCode}
                  , CHG_USER_ID  = #{uniqId}
                  , CHG_DATE  = NOW()
                  WHERE BBS_ID  = #{bbsId}

UPDATE ARMBORD
   SET STTUS_CODE = 'D'
     , CHG_USER_ID = #{uniqId}
     , CHG_DATE = NOW()
 WHERE BBS_ID = #{bbsId}
